-- Expansión grande del catálogo custom_foods (2026-06-12):
--   1. Bebidas y snacks de MARCA frecuentes (Monster, Red Bull, Coca-Cola, etc.)
--      para que el buscador devuelva resultados cuando el usuario tipea marcas.
--   2. Platos CASEROS típicos por país LATAM y España, para que la IA con dieta
--      "Casero" arme cenas/almuerzos coherentes con lo que se come en una casa.
--
-- Macros aproximadas de etiqueta/USDA/INTA. Se usa ON CONFLICT por (name)
-- evitado a propósito: name no tiene unique. Para idempotencia, se elimina
-- primero por name normalizado si ya existe.

DELETE FROM public.custom_foods
WHERE name_normalized IN (
  -- bebidas marca
  'monster energy original','monster ultra zero','red bull lata',
  'red bull sugar free','coca cola lata','coca cola zero lata',
  'sprite lata','fanta naranja lata','pepsi lata','pepsi black lata',
